use std::process::Command;
use std::path::{Path, PathBuf};

fn convert_file(filename: &str, desired_format: &str) -> Result<String, String> {
    let input_path = Path::new(filename);
    let file_stem = input_path.file_stem()
        .and_then(|s| s.to_str())
        .ok_or_else(|| format!("Invalid input filename: {}", filename))?;

    let output_file_name = format!("{}.{}", file_stem, desired_format);
    let output_path = input_path.with_file_name(&output_file_name);
    let output_path_str = output_path.to_str()
        .ok_or_else(|| format!("Failed to create output path string for {}", output_path.display()))?
        .to_string();

    let mut command_builder: Command;

    match desired_format.to_lowercase().as_str() {
        // Audio/Video conversion using ffmpeg
        "mp3" | "wav" | "flac" | "aac" | "ogg" | "mp4" | "avi" | "mov" | "webm" => {
            command_builder = Command::new("ffmpeg");
            command_builder.args(&["-i", filename, &output_path_str]);
        }
        // Image conversion using ImageMagick's convert
        "jpg" | "jpeg" | "png" | "gif" | "webp" | "bmp" | "tiff" => {
            command_builder = Command::new("convert");
            command_builder.args(&[filename, &output_path_str]);
        }
        // Document conversion using pandoc
        "pdf" | "docx" | "odt" | "html" | "md" | "txt" | "epub" => {
            command_builder = Command::new("pandoc");
            // Pandoc typically uses -o for output
            command_builder.args(&[filename, "-o", &output_path_str]);
        }
        _ => return Err(format!("Unsupported desired format: {}. Ensure the corresponding conversion tool is installed and in your PATH.", desired_format)),
    }

    let output = command_builder.output().map_err(|e| {
        format!(
            "Failed to execute command for format '{}'. Is the tool installed and in your PATH? Error: {}",
            desired_format, e
        )
    })?;

    if output.status.success() {
        Ok(output_path_str)
    } else {
        let stderr = String::from_utf8_lossy(&output.stderr);
        let stdout = String::from_utf8_lossy(&output.stdout);
        Err(format!(
            "Conversion command failed with exit code: {:?}\nStderr: {}\nStdout: {}",
            output.status.code(),
            stderr,
            stdout
        ))
    }
}